// Validează input-ul și mapează platform → marketplace
const body = $input.first().json.body || {};
const platform = (body.platform || 'emag').toLowerCase();
const platformMap = {
  'emag': 'emag_ro',
  'trendyol': 'trendyol_ro',
  'temu': 'temu_ro'
};
const marketplace = platformMap[platform] || (platform + '_ro');
const categoryId = String(body.categoryId || '').trim();
const asin = String(body.asin || '').trim();

// Trunchiază descrierea (strip HTML) la ~800 chars
function stripHtml(s) { return String(s || '').replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim(); }
const title = stripHtml(body.title).slice(0, 300);
const description = stripHtml(body.description).slice(0, 800);
const images = Array.isArray(body.images) ? body.images.slice(0, 3) : [];

if (!categoryId) {
  return [{ json: { _error: 'missing categoryId', attributes: { [platform]: {} } } }];
}

return [{ json: { marketplace, categoryId, asin, platform, title, description, images } }];

const https = require('https');
const http = require('http');
const { URL } = require('url');

// ─── CONFIGURARE API ────────────────────────────────────────────────────────
// Cheia Gemini: citită DIN env var (setează GEMINI_API_KEY în config-ul n8n,
// ex: ~/.n8n/.env sau variables în Docker). Fallback hardcodat DOAR pentru debug local.
const GEMINI_API_KEY = process.env.GEMINI_API_KEY || 'PUNE_GEMINI_API_KEY_AICI';
const MODEL_PRIMARY  = 'gemini-3.1-flash-lite-preview';
const MODEL_FALLBACK = 'gemini-flash-latest';
// ────────────────────────────────────────────────────────────────────────────

if (!GEMINI_API_KEY || GEMINI_API_KEY === 'PUNE_GEMINI_API_KEY_AICI') {
  const prep = $('Prepare Input').first().json;
  return [{ json: {
    _error: 'GEMINI_API_KEY missing. Set it in n8n env (process.env.GEMINI_API_KEY) or replace the placeholder in the Call Gemini Code node.',
    attributes: { [prep.platform || 'emag']: {} }
  } }];
}

function httpsRequest(options, postBody) {
  return new Promise((resolve, reject) => {
    const lib = options.protocol === 'http:' ? http : https;
    const req = lib.request(options, res => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => resolve({ status: res.statusCode, headers: res.headers, body: Buffer.concat(chunks) }));
    });
    req.on('error', reject);
    if (postBody) req.write(postBody);
    req.end();
  });
}

function fetchImageBase64(url) {
  return new Promise(async (resolve) => {
    try {
      const u = new URL(url);
      const res = await httpsRequest({
        protocol: u.protocol,
        hostname: u.hostname,
        path: u.pathname + (u.search || ''),
        method: 'GET',
        headers: { 'User-Agent': 'Mozilla/5.0 off-site-dev' }
      });
      if (res.status !== 200) return resolve(null);
      const contentType = (res.headers['content-type'] || 'image/jpeg').split(';')[0].trim();
      if (!contentType.startsWith('image/')) return resolve(null);
      resolve({ mimeType: contentType, data: res.body.toString('base64') });
    } catch (e) { resolve(null); }
  });
}

async function callGemini(model, reqBodyStr) {
  const res = await httpsRequest({
    hostname: 'generativelanguage.googleapis.com',
    path: `/v1beta/models/${model}:generateContent?key=${GEMINI_API_KEY}`,
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Content-Length': Buffer.byteLength(reqBodyStr)
    }
  }, reqBodyStr);
  // Orice non-2xx e eroare (inclusiv 401 pe cheie invalidă și 400 pe model inexistent).
  // Înainte treceam peste 4xx silențios ceea ce făcea ca output-ul să fie gol fără nicio indicație.
  if (res.status < 200 || res.status >= 300) {
    const snippet = res.body.toString('utf8').slice(0, 500);
    throw new Error(`HTTP ${res.status} from Gemini (${model}): ${snippet}`);
  }
  return res;
}

const prep = $('Prepare Input').first().json;
const { platform, title, description, images } = prep;

const rows = $input.all().map(i => i.json).filter(r => r && r.characteristic_id != null);
if (!rows.length) {
  return [{ json: { attributes: { [platform]: {} } } }];
}

const chars = rows.map(row => {
  let values = row.attr_values || [];
  if (typeof values === 'string') { try { values = JSON.parse(values); } catch(e) { values = []; } }
  const names = values.map(v => v && v.name).filter(Boolean);
  return {
    id: String(row.characteristic_id),
    name: row.characteristic_name,
    required: row.is_mandatory === true,
    allowsCustom: row.allows_custom === true,
    values: names
  };
});

const systemInstruction = `Ești un asistent de completare atribute pentru produse e-commerce. Primești titlul, descrierea și imaginile unui produs, plus o listă de caracteristici care trebuie completate pentru o categorie de marketplace.

Reguli stricte:
1. Pentru fiecare caracteristică din listă, încearcă să extragi valoarea din titlu, descriere sau imagini.
2. Dacă caracteristica are "values" non-gol (listă de valori predefinite), alege EXACT o valoare din acea listă (match semantic, nu literal).
3. Dacă NU există match bun în "values" ȘI allowsCustom=true, poți returna o valoare custom (scurt, 1-3 cuvinte).
4. Dacă NU există match ȘI allowsCustom=false, NU include caracteristica în output.
5. Dacă NU poți deduce o valoare (informație lipsă), NU include caracteristica.
6. Returnează DOAR JSON valid în formatul: {"filled": {"<id>": "<valoare>", ...}}
7. NU returna explicații, doar JSON.`;

const userText = `Titlu produs: ${title}\n\nDescriere produs: ${description}\n\nCaracteristici de completat (JSON):\n${JSON.stringify(chars)}`;

const imageResults = await Promise.all(images.map(fetchImageBase64));
const imageParts = imageResults.filter(Boolean).map(img => ({ inlineData: { mimeType: img.mimeType, data: img.data } }));

const reqBody = {
  systemInstruction: { parts: [{ text: systemInstruction }] },
  contents: [{ role: 'user', parts: [{ text: userText }, ...imageParts] }],
  generationConfig: {
    temperature: 0.2,
    responseMimeType: 'application/json',
    responseSchema: {
      type: 'object',
      properties: { filled: { type: 'object', additionalProperties: { type: 'string' } } },
      required: ['filled']
    }
  }
};

const reqBodyStr = JSON.stringify(reqBody);
let geminiResponse;
let lastError = null;
try {
  geminiResponse = await callGemini(MODEL_PRIMARY, reqBodyStr);
} catch (err) {
  lastError = err;
  console.log('[Gemini primary failed]', err.message);
  try {
    geminiResponse = await callGemini(MODEL_FALLBACK, reqBodyStr);
  } catch (err2) {
    console.log('[Gemini fallback failed]', err2.message);
    return [{ json: {
      _error: 'gemini failed: ' + err2.message,
      _primaryError: lastError ? lastError.message : null,
      attributes: { [platform]: {} }
    } }];
  }
}

let filled = {};
try {
  const parsed = JSON.parse(geminiResponse.body.toString('utf8'));
  const text = parsed?.candidates?.[0]?.content?.parts?.[0]?.text;
  if (text) {
    const json = JSON.parse(text);
    if (json && typeof json.filled === 'object' && json.filled) filled = json.filled;
  }
} catch (e) {
  const bodySnippet = geminiResponse.body.toString('utf8').slice(0, 500);
  console.log('[Gemini parse failed]', e.message, bodySnippet);
  return [{ json: { _error: 'parse failed: ' + e.message, _bodySnippet: bodySnippet, attributes: { [platform]: {} } } }];
}

return [{ json: { attributes: { [platform]: filled } } }];
